(()=>{"use strict";const e=document.documentElement,t=document.getElementById("themeToggle"),o=localStorage.getItem("theme")||"dark";e.setAttribute("data-theme",o),t.addEventListener("click",()=>{const t="dark"===e.getAttribute("data-theme")?"light":"dark";e.setAttribute("data-theme",t),localStorage.setItem("theme",t)});const l=document.getElementById("hamburger"),s=document.getElementById("mobileNav");l.addEventListener("click",()=>{l.classList.toggle("open"),s.classList.toggle("open"),document.body.style.overflow=s.classList.contains("open")?"hidden":""}),window.closeMenu=function(){l.classList.remove("open"),s.classList.remove("open"),document.body.style.overflow=""};const c=document.querySelectorAll(".reveal"),n=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&(e.target.classList.add("visible"),e.target.querySelectorAll(".skill-fill").forEach(e=>{e.style.width=e.dataset.width+"%"}))})},{threshold:.12});c.forEach(e=>n.observe(e));const r=document.querySelectorAll("section[id]"),a=document.querySelectorAll(".navbar a");window.addEventListener("scroll",()=>{let e="";r.forEach(t=>{window.scrollY>=t.offsetTop-200&&(e=t.id)}),a.forEach(t=>{t.classList.toggle("active",t.getAttribute("href")==="#"+e)})})})();